async fn someday_maybe_page_returns_200_with_nav() {
    let app = spawn_app().await;
    let client = register_and_login(
        &app.address,
        "somedaymaybe@example.com",
        "securepassword123",
    )
    .await;
    assert_gtd_page(
        &client,
        &app.address,
        "/someday-maybe",
        "Someday/Maybe",
        "someday_maybe",
