    AuthenticatedUser(_user_id): AuthenticatedUser,
) -> Result<impl IntoResponse, GtdPlaceholderError> {
    let template = GtdPlaceholderTemplate {
        current_page: "inbox",
        page_title: "Inbox -- Todo List",
